import{_ as e,o as i,c as a,a3 as r}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"2. Production (Distributor)","description":"","frontmatter":{"title":"2. Production (Distributor)"},"headers":[],"relativePath":"en/advertisers/dedicated-email/2-creation-distributeur.md","filePath":"en/advertisers/dedicated-email/2-creation-distributeur.md"}'),o={name:"en/advertisers/dedicated-email/2-creation-distributeur.md"};function n(s,t,d,l,c,h){return i(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="step-2-production-co-branding" tabindex="-1">Step 2: Production &amp; Co-branding <a class="header-anchor" href="#step-2-production-co-branding" aria-label="Permalink to &quot;Step 2: Production &amp; Co-branding&quot;">​</a></h1><p>Once your brief is sent, the distributor takes over to design the email.</p><hr><h2 id="why-aren-t-you-the-one-creating-the-email" tabindex="-1">Why aren&#39;t you the one creating the email? <a class="header-anchor" href="#why-aren-t-you-the-one-creating-the-email" aria-label="Permalink to &quot;Why aren&#39;t you the one creating the email?&quot;">​</a></h2><p><strong>The power of endorsement (recommendation).</strong></p><p>The goal is not to send a raw ad, but a recommendation from a trusted partner. The distributor&#39;s subscribers trust them — to maximize open and click rates, the email must follow the visual codes and usual tone of the newsletter they receive every week.</p><hr><h2 id="what-will-your-campaign-look-like" tabindex="-1">What will your campaign look like? <a class="header-anchor" href="#what-will-your-campaign-look-like" aria-label="Permalink to &quot;What will your campaign look like?&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">✅ Expected result (Native)</th><th style="text-align:left;">❌ What is avoided (Full Brand)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Partner Header</strong> — Distributor&#39;s logo and menu at the top, to reassure the subscriber</td><td style="text-align:left;">100% branded email to your site&#39;s colors, without partner mention</td></tr><tr><td style="text-align:left;"><strong>Intro Editorial</strong> — The distributor writes a hook sentence (<em>&quot;Our favorite...&quot;</em>)</td><td style="text-align:left;">Lack of contextualization by the distributor</td></tr><tr><td style="text-align:left;"><strong>Your assets</strong> — Visuals and offer integrated in the center, with the partner&#39;s fonts and buttons</td><td style="text-align:left;">Cognitive dissonance: the subscriber doesn&#39;t understand why they&#39;re receiving this email</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Avoid Full Brand</p><p>A Full Brand email without mentioning the partner confuses the subscriber, increases unsubscribes, and <strong>drops performance</strong>. Native co-branding is not a constraint — it&#39;s what makes the format effective.</p></div><hr><h2 id="the-production-workflow" tabindex="-1">The production workflow <a class="header-anchor" href="#the-production-workflow" aria-label="Permalink to &quot;The production workflow&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Design</h3><p>The distributor (or the getinside Studio) assembles the email using elements from your brief — visuals, offer, wording.</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Technical Integration</h3><p>Dynamic tracking links are generated and inserted. The HTML code is optimized for deliverability and responsiveness.</p></div></div><div class="gi-step"><div class="gi-step-num done">3</div><div class="gi-step-body"><h3>Internal Review</h3><p>The getinside team checks technical quality before submitting the result for your validation.</p></div></div><hr><h2 id="your-links-are-dynamic" tabindex="-1">Your links are dynamic <a class="header-anchor" href="#your-links-are-dynamic" aria-label="Permalink to &quot;Your links are dynamic&quot;">​</a></h2><p>Made a mistake in the brief? Changing landing page at the last minute?</p><div class="tip custom-block"><p class="custom-block-title">Don&#39;t panic — edit anytime</p><p>Email tracking links are <strong>dynamic</strong>, like getinside QR codes. You can modify the final destination URL at any time in the <strong>&quot;Configuration and Tracking&quot;</strong> tab of your campaign — even if the distributor has already embedded the link.</p></div><hr><h2 id="what-s-next" tabindex="-1">What&#39;s next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next?&quot;">​</a></h2><p>As soon as the creative is ready and technically validated, you receive a notification to proceed to Proof (BAT) validation.</p><p>→ Next step: <a href="./3-validation-diffusion.html">Validation &amp; Broadcast</a></p>',23)])])}const p=e(o,[["render",n]]);export{m as __pageData,p as default};
